import{_ as i,C as a,o,c as l,E as n,w as r,a2 as p}from"./chunks/framework.FJfr0oZU.js";const q=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"api/api.md","filePath":"api/api.md","lastUpdated":1779983670000}'),c={name:"api/api.md"};function d(u,e,h,g,f,k){const t=a("OASpec"),s=a("ClientOnly");return o(),l("div",null,[n(s,null,{default:r(()=>[n(t,{"spec-url":"../openapi.json"})]),_:1}),e[0]||(e[0]=p(`<h2 id="implementation-details" tabindex="-1">Implementation Details <a class="header-anchor" href="#implementation-details" aria-label="Permalink to &quot;Implementation Details&quot;">​</a></h2><p>The TORCH REST API follows the <a href="http://hl7.org/fhir/R5/async-bulk.html" target="_blank" rel="noreferrer">Asynchronous Bulk Data Request Pattern</a>.</p><h3 id="extract-data-kick-off" tabindex="-1">$extract-data Kick-off <a class="header-anchor" href="#extract-data-kick-off" aria-label="Permalink to &quot;$extract-data Kick-off&quot;">​</a></h3><p>The <code>$extract-data</code> endpoint initiates the extraction. It expects a FHIR <code>Parameters</code> resource containing a Base64 encoded <strong>CRTDL</strong> definition. resource with a <strong><em>crtdl</em></strong> parameter containing a valueBase64Binary <a href="https://github.com/medizininformatik-initiative/clinical-resource-transfer-definition-language" target="_blank" rel="noreferrer">CRTDL</a>. In all examples torch is configured with the base url <strong><code>http://localhost:8080</code></strong>.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/create-parameters.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/test/resources/CRTDL/CRTDL_observation.json</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;http://localhost:8080/fhir/$extract-data&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/fhir+json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre></div><h2 id="request-body-structure" tabindex="-1">Request Body Structure <a class="header-anchor" href="#request-body-structure" aria-label="Permalink to &quot;Request Body Structure&quot;">​</a></h2><p>The Parameters resource created by <a href="https://github.com/medizininformatik-initiative/torch/blob/main/scripts/create-parameters.sh" target="_blank" rel="noreferrer"><code>create-parameters.sh</code></a> look like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;resourceType&quot;: &quot;Parameters&quot;,</span></span>
<span class="line"><span>  &quot;parameter&quot;: [</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>      &quot;name&quot;: &quot;crtdl&quot;,</span></span>
<span class="line"><span>      &quot;valueBase64Binary&quot;: &quot;&lt;Base64 encoded CRTDL&gt;&quot;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>  ]</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Optionally patient ids can be submitted for a known cohort, bypassing the cohort selection in the CRTDL:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;resourceType&quot;: &quot;Parameters&quot;,</span></span>
<span class="line"><span>  &quot;parameter&quot;: [</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>      &quot;name&quot;: &quot;crtdl&quot;,</span></span>
<span class="line"><span>      &quot;valueBase64Binary&quot;: &quot;&lt;Base64 encoded CRTDL&gt;&quot;</span></span>
<span class="line"><span>    },</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>      &quot;name&quot;: &quot;patient&quot;,</span></span>
<span class="line"><span>      &quot;valueString&quot;: &quot;&lt;Patient Id 1&gt;&quot;</span></span>
<span class="line"><span>    },</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>      &quot;name&quot;: &quot;patient&quot;,</span></span>
<span class="line"><span>      &quot;valueString&quot;: &quot;&lt;Patient Id 2&gt;&quot;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>  ]</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="result-files" tabindex="-1">Result Files <a class="header-anchor" href="#result-files" aria-label="Permalink to &quot;Result Files&quot;">​</a></h3><p>Upon successful completion, the data extraction results consist of <strong>multiple NDJSON files</strong>:</p><ul><li><strong>One NDJSON file per patient batch</strong>, each containing <strong>FHIR transaction Bundles</strong></li><li><strong>One <code>core.ndjson</code> file</strong>, containing a <strong>single FHIR transaction Bundle</strong> with all <strong>non-patient-specific resources</strong></li></ul><h4 id="patient-batch-files" tabindex="-1">Patient Batch Files <a class="header-anchor" href="#patient-batch-files" aria-label="Permalink to &quot;Patient Batch Files&quot;">​</a></h4><p>Each patient batch NDJSON file contains:</p><ul><li><strong>One transaction Bundle per patient</strong></li><li>Each Bundle includes: <ul><li>exactly one <code>Patient</code> resource</li><li>all patient-specific resources extracted according to the CRTDL (e.g. <code>Encounter</code>, <code>Condition</code>, <code>Observation</code>, etc.)</li></ul></li></ul><p>Patient batch files can be processed <strong>independently and in any order</strong>.</p><h4 id="core-bundle-file" tabindex="-1">Core Bundle File <a class="header-anchor" href="#core-bundle-file" aria-label="Permalink to &quot;Core Bundle File&quot;">​</a></h4><p>The <code>core.ndjson</code> file contains:</p><ul><li>a single transaction Bundle</li><li>all <strong>non-patient-specific resources</strong> (e.g. shared reference data such as <code>Medication</code>)</li></ul><p>For <strong>referential integrity</strong>, <code>core.ndjson</code> <strong>must be processed before</strong> any patient batch files.<br> For this reason, the provided <a href="./../getting-started.html#transfer-script">transfer script</a> uploads <code>core.ndjson</code> first.</p><p>If <code>core.ndjson</code> contains resources but <strong>no patient batch files are present</strong>, this indicates that:</p><blockquote><p><strong>No patient survived the extraction</strong>, but core (non-patient) resources were still loaded.</p></blockquote><hr><h3 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h3><p>Given:</p><ul><li>Bundle size: <code>20</code></li><li><code>100</code> patients</li><li>Per patient: <ul><li><code>1</code> Encounter</li><li><code>1</code> Diagnosis</li></ul></li><li>Shared references: <ul><li><code>30</code> Medication resources</li></ul></li></ul><p>The extraction result will contain:</p><ul><li><strong>5 patient batch NDJSON files</strong> (each containing 20 transaction Bundles)</li><li><strong>1 <code>core.ndjson</code> file</strong></li></ul><p>Each <strong>patient batch file</strong> contains:</p><ul><li>one transaction Bundle per patient</li><li>each Bundle includes: <ul><li><code>1</code> Patient</li><li><code>≥1</code> Diagnosis</li><li><code>≥1</code> Encounter</li></ul></li></ul><p>The <strong><code>core.ndjson</code></strong> contains:</p><ul><li>a single transaction Bundle</li><li><code>30</code> Medication resources</li></ul>`,33))])}const b=i(c,[["render",d]]);export{q as __pageData,b as default};
